import { MailboxEntityList } from "./mailbox-entity-list";
import { MailboxEventList } from "./mailbox-event-list";

type MailboxTab = "entities" | "events";

export function Mailbox() {
  const [activeTab, setActiveTab] = useState<MailboxTab>("entities");

  return (
    <aside className="flex w-80 flex-shrink-0 flex-col border-r">
      {/* Tab switcher */}
      <div className="flex shrink-0 border-b px-3 py-2">
        <button
          className={cn(
            "flex-1 rounded-md px-3 py-1.5 text-sm font-medium transition-colors",
            activeTab === "entities"
              ? "bg-accent text-accent-foreground"
              : "text-muted-foreground hover:text-foreground"
          )}
          onClick={() => setActiveTab("entities")}
          type="button"
        >
          Entities
        </button>
        <button
          className={cn(
            "flex-1 rounded-md px-3 py-1.5 text-sm font-medium transition-colors",
            activeTab === "events"
              ? "bg-accent text-accent-foreground"
              : "text-muted-foreground hover:text-foreground"
          )}
          onClick={() => setActiveTab("events")}
          type="button"
        >
          Events
        </button>
      </div>

      {/* List content */}
      <div className="min-h-0 flex-1 overflow-auto">
        {activeTab === "entities" ? <MailboxEntityList /> : <MailboxEventList />}
      </div>
    </aside>
  );
}

export function MailboxSkeleton() {
  return (
    <aside className="flex w-80 flex-shrink-0 flex-col border-r">
      <div className="flex shrink-0 border-b px-3 py-2">
        <Skeleton className="h-8 w-full rounded-md" />
      </div>
      <div className="flex-1 space-y-1 p-2">
        {Array.from({ length: 10 }, (_, i) => (
          <Skeleton className="h-16 w-full rounded-md" key={i} />
        ))}
      </div>
    </aside>
  );
}
```

#### 3. Mailbox Entity List (new file)

**File**: `apps/app/src/app/(app)/(org)/[slug]/_components/mailbox-entity-list.tsx`
**Changes**: Compact entity list with search, infinite scroll, and realtime — adapted from `EntitiesTable` but with local state filters and compact row rendering

Key differences from the existing `EntitiesTable`:
- Local state for search and category (not URL-synced via `nuqs`)
- Compact row rendering (no `<Table>`, uses div-based list items)
- Click navigates to `/{slug}/entity/[entityId]` (new singular path)
- No table headers — just a scrollable list
- Same `useSuspenseInfiniteQuery` + `useRealtime` data patterns
- Same debounced search (300ms), same live entity merge/dedup logic

The component should:
1. Hold `searchInput` and `category` as local `useState`
2. Use `useSuspenseInfiniteQuery` on `trpc.entities.list` with `{ category, limit: 30, search }`
3. Subscribe via `useRealtime` to `org-{clerkOrgId}` channel, `"org.entity"` events
4. Merge live entities with DB entities using `externalId` dedup (same pattern as `entities-table.tsx:121-140`)
5. Render a search `<Input>` at the top, then a scrollable list of `<MailboxEntityRow>` items
6. Show "Load more" button when `hasNextPage`

#### 4. Mailbox Event List (new file)

**File**: `apps/app/src/app/(app)/(org)/[slug]/_components/mailbox-event-list.tsx`
**Changes**: Compact event list — adapted from `EventsTable` with local state

Same pattern as `mailbox-entity-list.tsx` but for events:
1. Hold `searchInput` and `source` as local `useState`
2. Use `useSuspenseInfiniteQuery` on `trpc.events.list` with `{ source, limit: 30, search }`
3. Subscribe via `useRealtime` to `org-{clerkOrgId}` channel, `"org.event"` events
4. Merge live events with DB events using `id` dedup (same pattern as `events-table.tsx:148-165`)
5. Render search `<Input>` + scrollable `<MailboxEventRow>` list
6. Click navigates to `/{slug}/event/[eventId]` (new route, Phase 2)

#### 5. Mailbox Entity Row (new file)

**File**: `apps/app/src/app/(app)/(org)/[slug]/_components/mailbox-entity-row.tsx`
**Changes**: Compact entity row for the mailbox list

```tsx
"use client";

import { Badge } from "@repo/ui/components/ui/badge";
import { formatDistanceToNow } from "date-fns";
import type { Route } from "next";
import { useParams, useRouter } from "next/navigation";
import type { Entity } from "~/types";

export function MailboxEntityRow({ entity }: { entity: Entity }) {
  const router = useRouter();
  const params = useParams<{ slug: string }>();

  return (
    <button
      className="flex w-full flex-col gap-1 rounded-md px-3 py-2.5 text-left transition-colors hover:bg-accent"
      onClick={() =>
        router.push(`/${params.slug}/entity/${entity.externalId}` as Route)
      }

      type="button"
    >
      <div className="flex items-center gap-2">
        <Badge className="text-xs font-normal" variant="outline">
          {entity.category}
        </Badge>
        {entity.state && (
          <Badge className="text-xs font-normal" variant="secondary">
            {entity.state}
          </Badge>
        )}
      </div>
      <span className="truncate font-medium text-sm">{entity.key}</span>
      <div className="flex items-center gap-2 text-muted-foreground text-xs">
        <span className="tabular-nums">{entity.occurrenceCount}x</span>
        <span>
          {formatDistanceToNow(new Date(entity.lastSeenAt), {
            addSuffix: true,
          })}
        </span>
      </div>
    </button>
  );
}
```

#### 6. Mailbox Event Row (new file)

**File**: `apps/app/src/app/(app)/(org)/[slug]/_components/mailbox-event-row.tsx`
**Changes**: Compact event row for the mailbox list

```tsx
"use client";

import { EVENT_LABELS, PROVIDER_DISPLAY } from "@repo/app-providers/client";
import { Badge } from "@repo/ui/components/ui/badge";
import { formatDistanceToNow } from "date-fns";
import type { Route } from "next";
import { useParams, useRouter } from "next/navigation";
import { ProviderIcon } from "~/lib/provider-icon";

interface MailboxEventRowProps {
  event: {
    id: number;
    source: string;
    sourceType: string;
    sourceEvent: { title: string; occurredAt: string };
  };
}

export function MailboxEventRow({ event }: MailboxEventRowProps) {
  const router = useRouter();
  const params = useParams<{ slug: string }>();

  const display = (
    PROVIDER_DISPLAY as Record<string, (typeof PROVIDER_DISPLAY)[keyof typeof PROVIDER_DISPLAY] | undefined>
  )[event.source];
  const registryKey = `${event.source}:${event.sourceType}`;
  const eventLabel =
    (EVENT_LABELS as Record<string, string | undefined>)[registryKey] ??
    event.sourceType;

  return (
    <button
      className="flex w-full items-start gap-3 rounded-md px-3 py-2.5 text-left transition-colors hover:bg-accent"
      onClick={() =>
        router.push(`/${params.slug}/event/${event.id}` as Route)
      }
      type="button"
    >
      <div className="mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center">
        {display ? (
          <ProviderIcon className="h-4 w-4 text-muted-foreground" icon={display.icon} />
        ) : (
          <div className="h-4 w-4 rounded bg-muted" />
        )}
      </div>
      <div className="min-w-0 flex-1">
        <span className="block truncate font-medium text-sm">
          {event.sourceEvent.title}
        </span>
        <div className="mt-0.5 flex items-center gap-2">
          <Badge className="text-xs font-normal" variant="secondary">
            {eventLabel}
          </Badge>
          <span className="text-muted-foreground text-xs">
            {formatDistanceToNow(new Date(event.sourceEvent.occurredAt), {
              addSuffix: true,
            })}
          </span>
        </div>
      </div>
    </button>
  );
}
```

